import java.util.Arrays;
public class Sorter {
    public static int[] sortedCopy(int[] arr) {
        int[] result = arr;          // line A
        Arrays.sort(result);         // line B
        return result;
    }

    public static void main(String[] args) {
        int[] nums = {3, 1, 4};
        int[] sorted = sortedCopy(nums);
        System.out.println(nums[0]); // prints 1, expected 3
    }
}
